package flagutil

import "reflect"

// targetsString reports whether ft ultimately represents a string-valued
// target for flag binding. Handles:
//   - bare `string` (or named alias like `type Chain string`)
//   - `*string` (optional bare)
//   - `OptionalNullable[T]` where T's underlying kind is string — i.e. the
//     `map[bool]*T` shape Speakeasy uses for optional/nullable query params
//     like `--chain` on read endpoints
//
// Used by buildJSONField to decide when a user's bare value (`base`,
// `USDC`) should be auto-wrapped in JSON quotes before being fed to the
// JSON unmarshaller — otherwise a plain `--chain base` errors with
// "invalid character 'b' looking for beginning of value".
func targetsString(ft reflect.Type) bool {
	if ft == nil {
		return false
	}
	// `string` or named string alias.
	if ft.Kind() == reflect.String {
		return true
	}
	// `*string` (or named alias pointer).
	if ft.Kind() == reflect.Ptr && ft.Elem().Kind() == reflect.String {
		return true
	}
	// `OptionalNullable[T]` = `map[bool]*T`. Underlying T must be string-ish.
	if ft.Kind() == reflect.Map &&
		ft.Key().Kind() == reflect.Bool &&
		ft.Elem().Kind() == reflect.Ptr &&
		ft.Elem().Elem().Kind() == reflect.String {
		return true
	}
	return false
}
